# Category: insecure_crypto

from Cryptodome import Random, PKCS12
from Cryptodome.Cipher import AES
from Cryptodome.Util.Padding import pad, unpad
import base64
import os

def load_key():
    with open(os.environ['CONFIG_FILE'], 'rb') as f:
        key = PKCS12.load(f).get_privatekey()
    return key

def encrypt(card_number):
    key = load_key()
    iv = Random.new().read(AES.block_size)
    cipher = AES.new(key, AES.MODE_CBC, iv)
    encrypted = base64.b64encode(iv + cipher.encrypt(pad(card_number.encode(), AES.block_size)))
    return encrypted

def decrypt(encrypted):
    key = load_key()
    encrypted = base64.b64decode(encrypted)
    iv = encrypted[:AES.block_size]
    cipher = AES.new(key, AES.MODE_CBC, iv)
    return unpad(cipher.decrypt(encrypted[AES.block_size:]), AES.block_size).decode()